package com..derivatives.gateway;

import org.springframework.boot.SpringApplication;
import org.springframework.boot.autoconfigure.SpringBootApplication;
import org.springframework.cloud.gateway.route.RouteLocator;
import org.springframework.cloud.gateway.route.builder.RouteLocatorBuilder;
import org.springframework.context.annotation.Bean;

/**
 * Main Spring Boot application class for API Gateway
 * 
 * This service provides centralized routing, authentication, rate limiting,
 * and cross-cutting concerns for the  Derivatives Platform microservices.
 * 
 * @author  Derivatives Platform Team
 * @version 1.0.0
 */
@SpringBootApplication
public class ApiGatewayApplication {

    public static void main(String[] args) {
        SpringApplication.run(ApiGatewayApplication.class, args);
    }

    @Bean
    public RouteLocator customRouteLocator(RouteLocatorBuilder builder) {
        return builder.routes()
            // Document Processing Service Routes
            .route("document-processing", r -> r
                .path("/api/v1/documents/**")
                .uri("http://localhost:8081"))

            // Eligibility Engine Service Routes
            .route("eligibility-engine", r -> r
                .path("/api/v1/eligibility/**")
                .uri("http://localhost:8082"))

            // Trade Management Service Routes
            .route("trade-management", r -> r
                .path("/api/v1/trades/**")
                .uri("http://localhost:8083"))

            .build();
    }
}

